module sr_latch (  
    input wire S,  
    input wire R,  
    output reg obf_Q,  
    output wire Qn  
);  
    assign Qn = ~obf_Q;  

    always @(S, R) begin  
        if (S && ~R)  
            obf_Q <= 1'b1;  
        else if (~S && R)  
            obf_Q <= 1'b0;  
        // If both S and R are low, keep the previous state (no action)  
    end  
endmodule
